export const JSON_HEADERS = { 'Content-Type': 'application/json' };

/**
 * Specialized error that when thrown from a repository, signals the route
 * to return a 404 instead of a 500.
 */
export class NotFoundError extends Error {
    constructor(message: string) {
        super(message);
        this.name = 'NotFoundError';
    }
}

/**
 * Repository-thrown error that maps to a 409. Used by story 075's write paths
 * when the on-disk file has uncommitted edits and the write would clobber.
 */
export class ConflictError extends Error {
    constructor(message: string) {
        super(message);
        this.name = 'ConflictError';
    }
}

/**
 * Repository-thrown error that maps to a 503. Used when persistent ID collisions
 * exhaust the create retry budget or the host's `git` invocation fails entirely.
 */
export class UnavailableError extends Error {
    constructor(message: string) {
        super(message);
        this.name = 'UnavailableError';
    }
}

/** Maps to 400 — used when a repository rejects validated input on deeper inspection. */
export class BadRequestError extends Error {
    constructor(message: string) {
        super(message);
        this.name = 'BadRequestError';
    }
}

// --- HTTP contract (framework-agnostic, section-agnostic) ---

/**
 * Response DTO returned by every shared route handler. The adapter
 * (Express + offline dispatcher) writes this to its own response shape.
 */
export interface ApiResponse {
    status: number;
    body?: unknown;
    headers?: Record<string, string>;
}

/**
 * Decoded request context passed to every shared route handler.
 * Path parameters are extracted by the adapter before the handler runs,
 * so handlers never parse paths.
 */
export interface RouteContext {
    params: Record<string, string>;
    query: URLSearchParams;
    body: unknown;
}

// --- Response helpers ---

export abstract class AbstractRouteResponses {
    protected ok(body: unknown): ApiResponse {
        return { status: 200, body, headers: JSON_HEADERS };
    }

    protected created(body: unknown): ApiResponse {
        return { status: 201, body, headers: JSON_HEADERS };
    }

    protected noContent(): ApiResponse {
        return { status: 204 };
    }

    protected badRequest(error: string): ApiResponse {
        return { status: 400, body: { error }, headers: JSON_HEADERS };
    }

    protected notFound(error: string): ApiResponse {
        return { status: 404, body: { error }, headers: JSON_HEADERS };
    }

    protected unavailable(error: string): ApiResponse {
        return { status: 503, body: { error }, headers: JSON_HEADERS };
    }

    protected forbidden(error: string): ApiResponse {
        return { status: 403, body: { error }, headers: JSON_HEADERS };
    }
}
