import { parseInteger } from './validation-utils.js';

// --- Shared health API surface ---

/**
 * Every key in this union is a route that is implemented once in shared code
 * and consumed by both the Express server and the PWA offline router.
 *
 * Server-only routes (OpenFoodFacts proxy, Ollama estimation, calendar
 * activities) are NOT listed here — they are defined exclusively in
 * server/src/modules/sections/health/health.routes.ts.
 *
 * Story 116 — `/nutrition*` was renamed to `/consumption-entries*` and
 * `/food-library*` was renamed to `/food-items*` to mirror the new schema.
 */
export type HealthRouteKey =
    | 'GET /stats'
    | 'GET /activities'
    | 'GET /activities/:id'
    | 'POST /activities'
    | 'PATCH /activities/:id'
    | 'DELETE /activities/:id'
    | 'GET /consumption-entries/summary'
    | 'GET /consumption-entries'
    | 'GET /consumption-entries/:id'
    | 'POST /consumption-entries'
    | 'PATCH /consumption-entries/:id'
    | 'DELETE /consumption-entries/:id'
    | 'GET /food-items/search'
    | 'GET /food-items/recent'
    | 'GET /food-items/frequent'
    | 'GET /food-items/barcode/:barcode'
    | 'GET /food-items/:id'
    | 'POST /food-items'
    | 'POST /food-items/log-new'
    | 'PATCH /food-items/:id'
    | 'POST /food-items/:id/log'
    | 'GET /meals'
    | 'GET /meals/search'
    | 'GET /meals/:id'
    | 'POST /meals'
    | 'PATCH /meals/:id'
    | 'DELETE /meals/:id'
    | 'POST /meals/:id/log';

/** Exhaustive TypeScript interface ensuring all routes are implemented. */
export interface IHealthRoutes {
    'GET /stats'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /activities'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /activities/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /activities'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /activities/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /activities/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /consumption-entries/summary'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /consumption-entries'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /consumption-entries/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /consumption-entries'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /consumption-entries/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /consumption-entries/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-items/search'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-items/recent'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-items/frequent'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-items/barcode/:barcode'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-items/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /food-items'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /food-items/log-new'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /food-items/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /food-items/:id/log'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /meals'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /meals/search'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /meals/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /meals'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /meals/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /meals/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /meals/:id/log'(ctx: RouteContext): Promise<ApiResponse>;
}

