// --- Query validation ---

export interface ResolvedActivitiesQuery {
    mode: 'date' | 'range';
    fromDate: string;
    toDate: string;
    date?: string;
}

function isLeapYear(year: number): boolean {
    return year % 400 === 0 || (year % 4 === 0 && year % 100 !== 0);
}

export function isValidIsoDate(value: string): boolean {
    const match = value.match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if (!match) {
        return false;
    }

    const year = Number.parseInt(match[1], 10);
    const month = Number.parseInt(match[2], 10);
    const day = Number.parseInt(match[3], 10);

    if (month < 1 || month > 12 || day < 1) {
        return false;
    }

    const daysInMonth = [
        31,
        isLeapYear(year) ? 29 : 28,
        31,
        30,
        31,
        30,
        31,
        31,
        30,
        31,
        30,
        31,
    ];

    return day <= daysInMonth[month - 1];
}

export function resolveActivitiesQuery(
    query: URLSearchParams,
): { error: string } | { value: ResolvedActivitiesQuery } {
    const date = query.get('date');
    const from = query.get('from');
    const to = query.get('to');

    if (date && (from || to)) {
        return { error: 'Use either "date" or "from/to", not both' };
    }

    if ((from && !to) || (!from && to)) {
        return { error: 'Both "from" and "to" are required when using a date range' };
    }

    if (date) {
        if (!isValidIsoDate(date)) {
            return { error: 'Invalid "date" query parameter. Expected YYYY-MM-DD' };
        }
        return {
            value: {
                mode: 'date',
                date,
                fromDate: date,
                toDate: date,
            },
        };
    }

    if (from && to) {
        if (!isValidIsoDate(from) || !isValidIsoDate(to)) {
            return { error: 'Invalid "from" or "to" query parameter. Expected YYYY-MM-DD' };
        }
        if (from > to) {
            return { error: '"from" must be on or before "to"' };
        }
        return {
            value: {
                mode: 'range',
                fromDate: from,
                toDate: to,
            },
        };
    }

    return { error: 'Provide either "date" or "from"+"to" query parameters' };
}

// --- Abstract Base Class ---

export interface HealthRepositories {
    activities: HealthRepository;
    foodItems: FoodItemRepository;
    consumption: ConsumptionRepository;
    meals: MealRepository;
}

/**
 * Base class for health routing implementations.
 * Encapsulates shared validation logic and response helpers.
 * Subclasses implement context-specific behavior (server vs offline).
 */
export abstract class AbstractHealthRoutes extends AbstractRouteResponses implements IHealthRoutes {
    protected abstract readonly repos: HealthRepositories;

    // --- Stats ---

    async 'GET /stats'(): Promise<ApiResponse> {
        const today = Temporal.Now.plainDateISO();
        const todayStr = today.toString();
        const weekAgoStr = today.subtract({ days: 6 }).toString();
        const yearAgoStr = today.subtract({ days: 365 }).toString();

        const [activityDates, summary] = await Promise.all([
            this.repos.activities.getActivityDatesDescSince(yearAgoStr),
            this.repos.consumption.getDateRangeSummary(weekAgoStr, todayStr),
        ]);

        const dateSet = new Set(activityDates);
        let checkDate = today;
        if (!dateSet.has(checkDate.toString())) {
            checkDate = checkDate.subtract({ days: 1 });
        }
        let streak = 0;
        for (let i = 0; i < 365; i++) {
            if (dateSet.has(checkDate.toString())) {
                streak++;
                checkDate = checkDate.subtract({ days: 1 });
            } else {
                break;
            }
        }

        const activeDays = summary.filter((s) => s.total_calories > 0);
        const avgCalories7d = activeDays.length > 0
            ? activeDays.reduce((sum, s) => sum + s.total_calories, 0) / activeDays.length
            : 0;

        return this.ok({ streak_days: streak, avg_calories_7d: avgCalories7d });
    }

    // --- Activities ---

    async 'GET /activities'({ query }: RouteContext): Promise<ApiResponse> {
        const resolved = resolveActivitiesQuery(query);
        if ('error' in resolved) {
            return this.badRequest(resolved.error);
        }

        const { value } = resolved;
        if (value.mode === 'date') {
            return this.ok(await this.repos.activities.getActivitiesByDate(value.date!));
        }
        return this.ok(await this.repos.activities.getActivitiesByDateRange(value.fromDate, value.toDate));
    }

    async 'GET /activities/:id'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repos.activities.getActivityById(params.id));
    }

    async 'POST /activities'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as Partial<NewActivity>;
        if (!b.type || !b.source || !b.title || !b.date) {
            return this.badRequest('Type, source, title, and date are required');
        }
        const activity = await this.repos.activities.createActivity({
            type: b.type,
            source: b.source,
            title: b.title,
            description: b.description,
            date: b.date,
            duration_minutes: b.duration_minutes,
            calories_burned: b.calories_burned,
            external_id: b.external_id,
            metadata: b.metadata,
        });
        return this.created(activity);
    }

    async 'PATCH /activities/:id'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const existing = await this.repos.activities.getActivityById(params.id);
        if (existing.source !== 'manual') {
            return this.forbidden('Cannot edit synced activities');
        }
        const updated = await this.repos.activities.updateActivity(params.id, (requestBody ?? {}) as Partial<NewActivity>);
        return this.ok(updated);
    }

    async 'DELETE /activities/:id'({ params }: RouteContext): Promise<ApiResponse> {
        await this.repos.activities.getActivityById(params.id);
        await this.repos.activities.deleteActivity(params.id);
        return this.noContent();
    }

    // --- Consumption entries ---

    async 'GET /consumption-entries/summary'({ query }: RouteContext): Promise<ApiResponse> {
        const from = query.get('from');
        const to = query.get('to');
        if (!from || !to) {
            return this.badRequest('Both "from" and "to" query parameters are required');
        }
        return this.ok(await this.repos.consumption.getDateRangeSummary(from, to));
    }

    async 'GET /consumption-entries'({ query }: RouteContext): Promise<ApiResponse> {
        const date = query.get('date');
        const from = query.get('from');
        const to = query.get('to');

        if (from && to) {
            return this.ok(await this.repos.consumption.getByDateRange(from, to));
        }
        if (!date) {
            return this.badRequest('Date or from/to query parameters are required');
        }
        return this.ok(await this.repos.consumption.getByDate(date));
    }

    async 'GET /consumption-entries/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        return this.ok(await this.repos.consumption.getById(id));
    }

    async 'POST /consumption-entries'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as Partial<NewConsumptionEntry>;
        if (!b.date) return this.badRequest('date is required');
        if (!b.meal_type) return this.badRequest('meal_type is required');
        if (!b.food_item_id) return this.badRequest('food_item_id is required');
        if (typeof b.amount !== 'number' || !Number.isFinite(b.amount) || b.amount <= 0) {
            return this.badRequest('amount must be a positive number');
        }
        if (!MEAL_TYPES.includes(b.meal_type)) {
            return this.badRequest(`meal_type must be one of: ${MEAL_TYPES.join(', ')}`);
        }

        const foodItem = await this.repos.foodItems.findById(b.food_item_id);
        if (!foodItem) {
            return this.notFound(`Food item ${b.food_item_id} not found`);
        }

        const entry = await this.repos.consumption.createForFoodItem(foodItem, {
            date: b.date,
            meal_type: b.meal_type,
            amount: b.amount,
            overrides: {
                calories: b.calories,
                protein_g: b.protein_g,
                carbs_g: b.carbs_g,
                fat_g: b.fat_g,
                fiber_g: b.fiber_g,
                sugar_g: b.sugar_g,
                sodium_mg: b.sodium_mg,
                source_meal_id: b.source_meal_id,
                meal_occurrence_id: b.meal_occurrence_id,
            },
        });
        await this.repos.foodItems.markUsed(foodItem.id);
        return this.created(entry);
    }

    async 'PATCH /consumption-entries/:id'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        const updated = await this.repos.consumption.update(id, (requestBody ?? {}) as Partial<NewConsumptionEntry>);
        return this.ok(updated);
    }

    async 'DELETE /consumption-entries/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        await this.repos.consumption.getById(id);
        await this.repos.consumption.delete(id);
        return this.noContent();
    }

    // --- Food items ---

    async 'GET /food-items/search'({ query }: RouteContext): Promise<ApiResponse> {
        const q = (query.get('q') ?? '').trim();
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        if (!q) {
            return this.ok([]);
        }
        return this.ok(await this.repos.foodItems.search(q, limit));
    }

    async 'GET /food-items/recent'({ query }: RouteContext): Promise<ApiResponse> {
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        return this.ok(await this.repos.foodItems.recent(limit));
    }

    async 'GET /food-items/frequent'({ query }: RouteContext): Promise<ApiResponse> {
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        return this.ok(await this.repos.foodItems.frequent(limit));
    }

    async 'GET /food-items/barcode/:barcode'({ params }: RouteContext): Promise<ApiResponse> {
        const barcode = params.barcode.replace(/[^0-9]/g, '');
        if (!barcode) {
            return this.badRequest('Invalid barcode');
        }
        const item = await this.repos.foodItems.findByBarcode(barcode);
        if (!item || item.archived_at) {
            return this.notFound('Food item not found');
        }
        return this.ok(item);
    }

    async 'GET /food-items/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        return this.ok(await this.repos.foodItems.getById(id));
    }

    async 'POST /food-items'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as Partial<NewFoodItem>;
        if (!b.display_name) return this.badRequest('display_name is required');
        if (!b.source) return this.badRequest('source is required');
        if (typeof b.base_amount !== 'number' || !Number.isFinite(b.base_amount) || b.base_amount <= 0) {
            return this.badRequest('base_amount must be a positive number');
        }
        if (!b.base_unit || !FOOD_BASE_UNITS.includes(b.base_unit as FoodBaseUnit)) {
            return this.badRequest(`base_unit must be one of: ${FOOD_BASE_UNITS.join(', ')}`);
        }

        const item = await this.repos.foodItems.create({
            canonical_name: b.canonical_name ?? b.display_name,
            display_name: b.display_name,
            brand: b.brand,
            barcode: b.barcode,
            source: b.source,
            source_ref: b.source_ref,
            base_amount: b.base_amount,
            base_unit: b.base_unit,
            default_serving_amount: b.default_serving_amount,
            serving_label: b.serving_label,
            serving_quantity: b.serving_quantity,
            calories_per_base: b.calories_per_base,
            protein_g_per_base: b.protein_g_per_base,
            carbs_g_per_base: b.carbs_g_per_base,
            fat_g_per_base: b.fat_g_per_base,
            fiber_g_per_base: b.fiber_g_per_base,
            sugar_g_per_base: b.sugar_g_per_base,
            sodium_mg_per_base: b.sodium_mg_per_base,
            raw_json: b.raw_json,
        });
        return this.created(item);
    }

    async 'PATCH /food-items/:id'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) return this.badRequest('Invalid id');
        const b = (requestBody ?? {}) as Partial<NewFoodItem>;
        if (b.base_unit && !FOOD_BASE_UNITS.includes(b.base_unit as FoodBaseUnit)) {
            return this.badRequest(`base_unit must be one of: ${FOOD_BASE_UNITS.join(', ')}`);
        }
        if (b.base_amount !== undefined && (typeof b.base_amount !== 'number' || !Number.isFinite(b.base_amount) || b.base_amount <= 0)) {
            return this.badRequest('base_amount must be a positive number');
        }
        const updated = await this.repos.foodItems.update(id, b);
        return this.ok(updated);
    }

    async 'POST /food-items/log-new'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as { food?: Partial<NewFoodItem>; log?: { date?: string; meal_type?: MealType; amount?: number } };
        const food = b.food ?? {};
        const log = b.log ?? {};
        if (!food.display_name) return this.badRequest('food.display_name is required');
        if (!food.source) return this.badRequest('food.source is required');
        if (typeof food.base_amount !== 'number' || !Number.isFinite(food.base_amount) || food.base_amount <= 0) {
            return this.badRequest('food.base_amount must be a positive number');
        }
        if (!food.base_unit || !FOOD_BASE_UNITS.includes(food.base_unit as FoodBaseUnit)) {
            return this.badRequest(`food.base_unit must be one of: ${FOOD_BASE_UNITS.join(', ')}`);
        }
        if (!log.date) return this.badRequest('log.date is required');
        if (!log.meal_type || !MEAL_TYPES.includes(log.meal_type)) {
            return this.badRequest(`log.meal_type must be one of: ${MEAL_TYPES.join(', ')}`);
        }
        if (typeof log.amount !== 'number' || !Number.isFinite(log.amount) || log.amount <= 0) {
            return this.badRequest('log.amount must be a positive number');
        }
        const result = await this.repos.foodItems.createAndLog(
            {
                canonical_name: food.canonical_name ?? food.display_name,
                display_name: food.display_name,
                brand: food.brand,
                barcode: food.barcode,
                source: food.source,
                source_ref: food.source_ref,
                base_amount: food.base_amount,
                base_unit: food.base_unit,
                default_serving_amount: food.default_serving_amount,
                serving_label: food.serving_label,
                serving_quantity: food.serving_quantity,
                calories_per_base: food.calories_per_base,
                protein_g_per_base: food.protein_g_per_base,
                carbs_g_per_base: food.carbs_g_per_base,
                fat_g_per_base: food.fat_g_per_base,
                fiber_g_per_base: food.fiber_g_per_base,
                sugar_g_per_base: food.sugar_g_per_base,
                sodium_mg_per_base: food.sodium_mg_per_base,
                raw_json: food.raw_json,
            },
            { date: log.date, meal_type: log.meal_type, amount: log.amount },
        );
        return this.created(result);
    }

    async 'POST /food-items/:id/log'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) return this.badRequest('Invalid id');
        const b = (requestBody ?? {}) as { date?: string; meal_type?: MealType; amount?: number };
        if (!b.date || !b.meal_type) {
            return this.badRequest('date and meal_type are required');
        }
        if (!MEAL_TYPES.includes(b.meal_type)) {
            return this.badRequest(`meal_type must be one of: ${MEAL_TYPES.join(', ')}`);
        }

        const foodItem = await this.repos.foodItems.findById(id);
        if (!foodItem) {
            return this.notFound(`Food item ${id} not found`);
        }

        const amount = typeof b.amount === 'number' && Number.isFinite(b.amount) && b.amount > 0
            ? b.amount
            : foodItem.default_serving_amount ?? foodItem.serving_quantity ?? foodItem.base_amount;

        const entry = await this.repos.consumption.createForFoodItem(foodItem, {
            date: b.date,
            meal_type: b.meal_type,
            amount,
        });
        await this.repos.foodItems.markUsed(foodItem.id);
        return this.created(entry);
    }

    // --- Meals ---

    private validateMealPayload(b: Partial<NewMealWithIngredients>, { requireIngredients }: { requireIngredients: boolean }): ApiResponse | null {
        if (b.name !== undefined && (!b.name || !b.name.trim())) {
            return this.badRequest('name is required');
        }
        if (b.default_scale !== undefined && (typeof b.default_scale !== 'number' || !Number.isFinite(b.default_scale) || b.default_scale <= 0)) {
            return this.badRequest('default_scale must be a positive number');
        }
        if (b.ingredients !== undefined) {
            if (!Array.isArray(b.ingredients) || b.ingredients.length === 0) {
                return this.badRequest('ingredients must be a non-empty array');
            }
            for (const [i, ing] of b.ingredients.entries()) {
                if (!ing || typeof ing !== 'object') {
                    return this.badRequest(`ingredients[${i}] must be an object`);
                }
                if (!ing.food_item_id || typeof ing.food_item_id !== 'string') {
                    return this.badRequest(`ingredients[${i}].food_item_id is required`);
                }
                if (typeof ing.amount !== 'number' || !Number.isFinite(ing.amount) || ing.amount <= 0) {
                    return this.badRequest(`ingredients[${i}].amount must be a positive number`);
                }
            }
        } else if (requireIngredients) {
            return this.badRequest('ingredients must be a non-empty array');
        }
        return null;
    }

    async 'GET /meals'({ query }: RouteContext): Promise<ApiResponse> {
        const limit = parseInteger(query.get('limit') ?? '') ?? 50;
        return this.ok(await this.repos.meals.list({ limit }));
    }

    async 'GET /meals/search'({ query }: RouteContext): Promise<ApiResponse> {
        const q = query.get('q') ?? '';
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        return this.ok(await this.repos.meals.search(q, limit));
    }

    async 'GET /meals/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) return this.badRequest('Invalid id');
        return this.ok(await this.repos.meals.getById(id));
    }

    async 'POST /meals'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as Partial<NewMealWithIngredients>;
        if (!b.name || !b.name.trim()) return this.badRequest('name is required');
        const validation = this.validateMealPayload(b, { requireIngredients: true });
        if (validation) return validation;
        const meal = await this.repos.meals.create({
            name: b.name.trim(),
            notes: b.notes,
            default_scale: b.default_scale,
            image_path: b.image_path,
            ingredients: b.ingredients!,
        });
        return this.created(meal);
    }

    async 'PATCH /meals/:id'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) return this.badRequest('Invalid id');
        const b = (requestBody ?? {}) as Partial<NewMealWithIngredients>;
        const validation = this.validateMealPayload(b, { requireIngredients: false });
        if (validation) return validation;
        const updated = await this.repos.meals.update(id, b);
        return this.ok(updated);
    }

    async 'DELETE /meals/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) return this.badRequest('Invalid id');
        await this.repos.meals.getById(id);
        await this.repos.meals.delete(id);
        return this.noContent();
    }

    async 'POST /meals/:id/log'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) return this.badRequest('Invalid id');
        const b = (requestBody ?? {}) as { date?: string; meal_type?: MealType; scale?: number };
        if (!b.date) return this.badRequest('date is required');
        if (!b.meal_type) return this.badRequest('meal_type is required');
        if (!MEAL_TYPES.includes(b.meal_type)) {
            return this.badRequest(`meal_type must be one of: ${MEAL_TYPES.join(', ')}`);
        }
        if (b.scale !== undefined && (typeof b.scale !== 'number' || !Number.isFinite(b.scale) || b.scale <= 0)) {
            return this.badRequest('scale must be a positive number');
        }
        const result = await this.repos.meals.logMeal(id, {
            date: b.date,
            meal_type: b.meal_type,
            scale: b.scale,
        });
        return this.created(result);
    }
}
