import type { DbDriver } from '../types/db.js';
import type { Card, Deck, DeckStat, NewCard, NewDeck, NewReview, Review } from '../types/vietnamese.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

function toNonNegativeInt(value: number | null | undefined): number {
    if (typeof value !== 'number' || !Number.isFinite(value)) {
        return 0;
    }
    return Math.max(0, Math.floor(value));
}

export function createVietnameseRepository(driver: DbDriver) {
    const repository = {
        async getAllDecks(): Promise<Deck[]> {
            return driver.query<Deck>('SELECT * FROM decks ORDER BY name');
        },

        async getDeckStats(): Promise<DeckStat[]> {
            return driver.query<DeckStat>(`
                SELECT
                    d.id,
                    d.name,
                    d.description,
                    COUNT(c.id) AS total_cards,
                    COUNT(CASE WHEN lr.card_id IS NULL THEN 1 END) AS new_cards,
                    COUNT(CASE WHEN lr.card_id IS NOT NULL AND datetime(lr.due) <= datetime('now') THEN 1 END) AS due_cards
                FROM decks d
                LEFT JOIN cards c ON c.deck_id = d.id
                LEFT JOIN (
                    SELECT r.card_id, r.due
                    FROM reviews r
                    INNER JOIN (
                        SELECT card_id, MAX(created_at) AS max_created
                        FROM reviews
                        GROUP BY card_id
                    ) m ON r.card_id = m.card_id AND r.created_at = m.max_created
                ) lr ON lr.card_id = c.id
                GROUP BY d.id
                ORDER BY d.name
            `);
        },

        async findDeckById(id: string): Promise<Deck | null> {
            return driver.queryOne<Deck>('SELECT * FROM decks WHERE id = ?', [id]);
        },

        async getDeckById(id: string): Promise<Deck> {
            return driver.queryOne<Deck>('SELECT * FROM decks WHERE id = ?', [id], {
                notFound: () => new NotFoundError(`Deck ${id} not found`),
            });
        },

        async createDeck(deck: NewDeck): Promise<Deck> {
            const id = uuidv7();
            await driver.execute(
                'INSERT INTO decks (id, name, description) VALUES (?, ?, ?)',
                id,
                deck.name,
                deck.description ?? null,
            );
            return driver.queryOne<Deck>('SELECT * FROM decks WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created deck: ${id}`),
            });
        },

        async createDeckWithId(id: string, deck: NewDeck): Promise<Deck> {
            await driver.execute(
                'INSERT INTO decks (id, name, description) VALUES (?, ?, ?)',
                id,
                deck.name,
                deck.description ?? null,
            );
            return driver.queryOne<Deck>('SELECT * FROM decks WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created deck: ${id}`),
            });
        },

        async updateDeck(id: string, updates: Partial<NewDeck>): Promise<Deck> {
            await repository.getDeckById(id);

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowedFields = ['name', 'description'] as const;
            for (const field of allowedFields) {
                if (field in updates) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length > 0) {
                fields.push("updated_at = datetime('now')");
                values.push(id);
                await driver.execute(`UPDATE decks SET ${fields.join(', ')} WHERE id = ?`, ...values);
            }

            return driver.queryOne<Deck>('SELECT * FROM decks WHERE id = ?', [id], {
                notFound: () => new Error(`Deck ${id} not found after update`),
            });
        },

        async deleteDeck(id: string): Promise<boolean> {
            const result = await driver.execute('DELETE FROM decks WHERE id = ?', id);
            return result.changes > 0;
        },

        async getCardsByDeckId(deckId: string): Promise<Card[]> {
            return driver.query<Card>('SELECT * FROM cards WHERE deck_id = ? ORDER BY created_at', deckId);
        },

        async findCardById(id: string): Promise<Card | null> {
            return driver.queryOne<Card>('SELECT * FROM cards WHERE id = ?', [id]);
        },

        async getCardById(id: string): Promise<Card> {
            return driver.queryOne<Card>('SELECT * FROM cards WHERE id = ?', [id], {
                notFound: () => new NotFoundError(`Card ${id} not found`),
            });
        },

        async getAllCards(): Promise<Card[]> {
            return driver.query<Card>('SELECT * FROM cards ORDER BY created_at');
        },

        async createCard(card: NewCard): Promise<Card> {
            const id = uuidv7();
            await driver.execute(
                'INSERT INTO cards (id, deck_id, front, back, audio, notes) VALUES (?, ?, ?, ?, ?, ?)',
                id,
                card.deck_id,
                card.front,
                card.back,
                card.audio ?? null,
                card.notes ?? null,
            );
            return driver.queryOne<Card>('SELECT * FROM cards WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created card: ${id}`),
            });
        },

        async createCardWithId(id: string, card: NewCard): Promise<Card> {
            await driver.execute(
                'INSERT INTO cards (id, deck_id, front, back, audio, notes) VALUES (?, ?, ?, ?, ?, ?)',
                id,
                card.deck_id,
                card.front,
                card.back,
                card.audio ?? null,
                card.notes ?? null,
            );
            return driver.queryOne<Card>('SELECT * FROM cards WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created card: ${id}`),
            });
        },

        async updateCard(
            id: string,
            updates: Partial<Omit<NewCard, 'deck_id' | 'audio'>> & { audio?: string | null },
        ): Promise<Card> {
            await repository.getCardById(id);

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowedFields = ['front', 'back', 'audio', 'notes'] as const;
            for (const field of allowedFields) {
                if (field in updates) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length > 0) {
                fields.push("updated_at = datetime('now')");
                values.push(id);
                await driver.execute(`UPDATE cards SET ${fields.join(', ')} WHERE id = ?`, ...values);
            }

            return driver.queryOne<Card>('SELECT * FROM cards WHERE id = ?', [id], {
                notFound: () => new Error(`Card ${id} not found after update`),
            });
        },

        async deleteCard(id: string): Promise<boolean> {
            const result = await driver.execute('DELETE FROM cards WHERE id = ?', id);
            return result.changes > 0;
        },

        async getReviewsByCardId(cardId: string): Promise<Review[]> {
            return driver.query<Review>('SELECT * FROM reviews WHERE card_id = ? ORDER BY created_at DESC', cardId);
        },

        async getDueCards(deckId: string, limitNewCards = 10): Promise<Card[]> {
            const due = await driver.query<Card>(`
                SELECT c.* FROM cards c
                JOIN reviews r ON r.id = (
                    SELECT id FROM reviews WHERE card_id = c.id ORDER BY created_at DESC LIMIT 1
                )
                WHERE c.deck_id = ? AND datetime(r.due) <= datetime('now')
                ORDER BY datetime(r.due) ASC
            `, deckId);

            const newCards = await driver.query<Card>(`
                SELECT c.* FROM cards c
                LEFT JOIN reviews r ON r.card_id = c.id
                WHERE c.deck_id = ? AND r.id IS NULL
                ORDER BY c.created_at ASC
                LIMIT ?
            `, deckId, limitNewCards);

            return [...due, ...newCards];
        },

        async getDueCardsFromAllDecks(limitNewCards = 10): Promise<Card[]> {
            const due = await driver.query<Card>(`
                SELECT c.* FROM cards c
                JOIN reviews r ON r.id = (
                    SELECT id FROM reviews WHERE card_id = c.id ORDER BY created_at DESC LIMIT 1
                )
                WHERE datetime(r.due) <= datetime('now')
                ORDER BY datetime(r.due) ASC
            `);

            const newCards = await driver.query<Card>(`
                SELECT c.* FROM cards c
                LEFT JOIN reviews r ON r.card_id = c.id
                WHERE r.id IS NULL
                ORDER BY c.created_at ASC
                LIMIT ?
            `, limitNewCards);

            return [...due, ...newCards];
        },

        async getLatestReviewByCardId(cardId: string): Promise<Review | null> {
            return driver.queryOne<Review>(
                'SELECT * FROM reviews WHERE card_id = ? ORDER BY created_at DESC LIMIT 1',
                [cardId],
            );
        },

        async createReview(review: NewReview): Promise<Review> {
            const id = uuidv7();
            const scheduledDays = toNonNegativeInt(review.scheduled_days);
            const elapsedDays = toNonNegativeInt(review.elapsed_days);
            await driver.execute(
                `INSERT INTO reviews (id, card_id, state, stability, difficulty, scheduled_days, elapsed_days, rating, due, last_review)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                id,
                review.card_id,
                review.state ?? 'new',
                review.stability ?? 0,
                review.difficulty ?? 0,
                scheduledDays,
                elapsedDays,
                review.rating ?? null,
                review.due ?? Temporal.Now.instant().toString(),
                review.last_review ?? null,
            );
            return driver.queryOne<Review>('SELECT * FROM reviews WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created review: ${id}`),
            });
        },
    };

    return repository;
}

export type VietnameseRepository = ReturnType<typeof createVietnameseRepository>;
