export interface DbExecuteResult {
    changes: number;
    lastInsertRowid: number;
}

export interface DbDriver {
    query<T>(sql: string, ...params: unknown[]): Promise<T[]>;
    execute(sql: string, ...params: unknown[]): Promise<DbExecuteResult>;
    
    /**
     * Type-safe overloads for queryOne:
     * 1. Without options -> Returns T | null
     * 2. With notFound handler -> Returns T (narrowed, as it will throw if missing)
     * This is the idiomatic TypeScript way to narrow return types based on argument presence.
     */
    queryOne<T>(sql: string, params?: unknown[]): Promise<T | null>;
    queryOne<T>(sql: string, params: unknown[], options: { notFound: () => Error }): Promise<T>;
}

export abstract class BaseDbDriver implements DbDriver {
    abstract query<T>(sql: string, ...params: unknown[]): Promise<T[]>;
    abstract execute(sql: string, ...params: unknown[]): Promise<DbExecuteResult>;

    private inTransaction = false;

    /**
     * Catches double-BEGIN and orphan COMMIT/ROLLBACK on this driver instance.
     * See DLR #46 — does NOT catch interleaved statements from other callers
     * during a transaction's await window; that invariant is held by the caller.
     */
    protected checkTransactionPrecondition(sql: string): 'BEGIN' | 'END' | null {
        const match = /^\s*(BEGIN|COMMIT|ROLLBACK|END)\b/i.exec(sql);
        if (!match) return null;
        const kind = match[1].toUpperCase() === 'BEGIN' ? 'BEGIN' : 'END';
        if (kind === 'BEGIN' && this.inTransaction) {
            throw new Error(
                'DbDriver: BEGIN issued while a transaction is already open on this driver. ' +
                    'Multi-step transactions on a shared driver are not safe across awaits — see DLR #46.',
            );
        }
        if (kind === 'END' && !this.inTransaction) {
            throw new Error(
                `DbDriver: ${match[1].toUpperCase()} issued without an open transaction on this driver. See DLR #46.`,
            );
        }
        return kind;
    }

    protected markTransactionState(kind: 'BEGIN' | 'END' | null): void {
        if (kind === 'BEGIN') this.inTransaction = true;
        else if (kind === 'END') this.inTransaction = false;
    }

    async queryOne<T>(sql: string, params?: unknown[]): Promise<T | null>;
    async queryOne<T>(sql: string, params: unknown[], options: { notFound: () => Error }): Promise<T>;
    async queryOne<T>(
        sql: string,
        params: unknown[] = [],
        options: { notFound?: () => Error } = {},
    ): Promise<T | null> {
        const rows = await this.query<T>(sql, ...params);

        if (rows.length > 1) {
            throw new Error(`Expected at most 1 row, got ${rows.length} for query: ${sql}`);
        }

        if (rows.length === 0) {
            if (options.notFound) throw options.notFound();
            return null;
        }

        return rows[0];
    }
}
