export function asRecord(body: unknown): Record<string, unknown> {
    if (typeof body !== 'object' || body === null) {
        return {};
    }
    return body as Record<string, unknown>;
}

export function parseInteger(value: string): number | null {
    const parsed = Number.parseInt(value, 10);
    return Number.isNaN(parsed) ? null : parsed;
}

export function parsePositiveInteger(value: string | null, fallback: number): number {
    const parsed = Number(value ?? fallback);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

export function parseNonEmptyString(value: unknown): string | null {
    if (typeof value !== 'string') {
        return null;
    }
    const normalized = value.trim();
    return normalized.length > 0 ? normalized : null;
}

export function parseOptionalNonEmptyString(value: unknown): string | undefined {
    if (typeof value !== 'string') {
        return undefined;
    }
    const normalized = value.trim();
    return normalized.length > 0 ? normalized : undefined;
}

export function sanitizeText(value: string): string {
    return value.replace(/[\u0000-\u001F\u007F]/g, '').replace(/[<>]/g, '').trim();
}

export function parseRequiredSanitizedText(value: unknown): string | null {
    if (typeof value !== 'string') {
        return null;
    }
    const sanitized = sanitizeText(value);
    return sanitized.length > 0 ? sanitized : null;
}

export function parseOptionalSanitizedText(value: unknown): { valid: boolean; value?: string } {
    if (value === undefined || value === null) {
        return { valid: true, value: undefined };
    }
    if (typeof value !== 'string') {
        return { valid: false, value: undefined };
    }
    const sanitized = sanitizeText(value);
    return { valid: true, value: sanitized.length > 0 ? sanitized : undefined };
}
