import type { DbDriver } from '../types/db.js';
import type { SnapshotInfoBody } from '../api/sync-routes.js';

/**
 * `settings.sync.snapshot_generation` is a monotonic integer that ticks on
 * every server-side mutation of synced tables (today: inside every successful
 * `POST /api/sync/push` transaction). Story 133 — clients use it to gate
 * the binary `/snapshot` download via the cheap `/snapshot/info` endpoint.
 *
 * The PWA also reads its *local* value from the same `settings.sync.snapshot_generation`
 * row in its OPFS replica — the snapshot import brings the server's
 * generation along, so the local row literally records "the generation this
 * client's DB represents". No separate per-origin meta store is needed.
 */
export const SNAPSHOT_GENERATION_KEY = 'sync.snapshot_generation';

export function createSnapshotMetaRepository(driver: DbDriver) {
    const repository = {
        /**
         * UPSERT-bumps the generation by 1, intended to be called inside an
         * outer transaction so the bump is atomic with the write that caused
         * it. Fresh DB (no row) → 1; existing N → N+1.
         */
        async bumpGeneration(): Promise<void> {
            await driver.execute(
                `INSERT INTO settings (key, value, updated_at)
                 VALUES (?, '1', datetime('now'))
                 ON CONFLICT(key) DO UPDATE
                   SET value = CAST(value AS INTEGER) + 1,
                       updated_at = datetime('now')`,
                SNAPSHOT_GENERATION_KEY,
            );
        },

        /**
         * Read the current generation + its `updated_at` timestamp. Returns
         * `{ generation: 0, generated_at: <epoch> }` when the row is absent.
         * Server uses this to answer `GET /snapshot/info`; PWA uses it on
         * the local DB to know what generation its snapshot represents.
         */
        async readInfo(): Promise<SnapshotInfoBody> {
            const row = await driver.queryOne<{ value: string; updated_at: string }>(
                'SELECT value, updated_at FROM settings WHERE key = ?',
                [SNAPSHOT_GENERATION_KEY],
            );
            if (!row) {
                return { generation: 0, generated_at: new Date(0).toISOString() };
            }
            const parsed = Number.parseInt(row.value, 10);
            return {
                generation: Number.isFinite(parsed) ? parsed : 0,
                generated_at: row.updated_at,
            };
        },
    };
    return repository;
}
