export const STORY_SECTION_KEYS = [
    'story',
    'acceptanceCriteria',
    'storyPoints',
    'priority',
    'blockers',
    'dependencies',
    'designNotes',
] as const;

export type StorySectionKey = typeof STORY_SECTION_KEYS[number];

export const STORY_SECTION_HEADINGS: Record<StorySectionKey, string> = {
    story: 'Story',
    acceptanceCriteria: 'Acceptance Criteria',
    storyPoints: 'Story Points',
    priority: 'Priority',
    blockers: 'Blockers',
    dependencies: 'Dependencies',
    designNotes: 'Design Notes',
};

export const STORY_SECTION_HEADING_TO_KEY: Record<string, StorySectionKey> = {
    'Story': 'story',
    'Acceptance Criteria': 'acceptanceCriteria',
    // Tolerate the legacy template typo. Files written before story 075 may still use this spelling.
    'Aceptance Criteria': 'acceptanceCriteria',
    'Story Points': 'storyPoints',
    'Priority': 'priority',
    'Blockers': 'blockers',
    'Dependencies': 'dependencies',
    'Design Notes': 'designNotes',
};

export interface Story {
    id: string;
    title: string;
    /**
     * Verbatim text from the start of the file up to (but not including) the first `## ` heading.
     * Preserved so parse → serialize → parse round-trips on stories with non-canonical preambles
     * (e.g. `# Subtask: ...` files). On title changes, `setStoryTitle` rewrites only the matching
     * `^# ` line inside this string. Authors generally don't see this field; PWA reads `title`.
     */
    rawPreamble: string;
    sections: Partial<Record<StorySectionKey, string>>;
    /**
     * Headings outside the template, preserved verbatim so parse → serialize → parse round-trips.
     * Keys are the literal heading text; values are the section body (without surrounding newlines).
     * Order is preserved by insertion order.
     */
    extraSections: Record<string, string>;
}

export type ScrumboardLaneId =
    | 'active-sprint'
    | 'completed'
    | 'high-priority'
    | 'medium-priority'
    | 'low-priority'
    | 'superseded';

export type ScrumboardBacklogLaneId = Exclude<ScrumboardLaneId, 'active-sprint' | 'completed'>;

export interface ScrumboardTableItem {
    id: string;
    title: string;
    /** Free-text Status column ("In Progress", "Done", "Planning", etc). */
    status: string;
    points: number | null;
}

export interface ScrumboardChecklistItem {
    /** Empty string for entries that have no numeric ID (e.g. "Agenda CRUD follow-up"). */
    id: string;
    title: string;
    points: number | null;
    /** Trailing note after points/title, trimmed of separator. `null` when absent. */
    note: string | null;
    /** Verbatim source separator between bold/points and note. `null` when no note. */
    noteSeparator: ' — ' | ': ' | null;
    /** Task-list checkbox state. */
    checked: boolean;
    /** Whether the title was wrapped in `~~...~~` (used for superseded entries). */
    strikethrough: boolean;
}

export interface ScrumboardTableLane {
    items: ScrumboardTableItem[];
}

export interface ScrumboardChecklistLane {
    heading: string;
    items: ScrumboardChecklistItem[];
}

export interface WritableScrumboard {
    sprintName: string | null;
    sprintGoal: string | null;
    activeSprint: ScrumboardTableLane;
    completed: ScrumboardTableLane;
    backlog: {
        'high-priority': ScrumboardChecklistLane;
        'medium-priority': ScrumboardChecklistLane;
        'low-priority': ScrumboardChecklistLane;
        superseded: ScrumboardChecklistLane;
    };
}

export interface ScrumboardLaneMove {
    id: string;
    fromLane: ScrumboardLaneId;
    toLane: ScrumboardLaneId;
    /** Optional 0-based insertion index in the destination lane. Appends if omitted. */
    position?: number;
}

export interface PatchScrumboardBody {
    sprintName?: string;
    sprintGoal?: string;
    moves?: ScrumboardLaneMove[];
}

export interface PatchStoryBody {
    title?: string;
    sections?: Partial<Record<StorySectionKey, string>>;
}

export interface CreateStoryBody {
    title: string;
    sections?: Partial<Record<StorySectionKey, string>>;
    backlogLane?: ScrumboardBacklogLaneId;
}

export interface CreateStoryResponse {
    id: string;
    canonicalMarkdown: string;
}

export interface StoryResponse {
    id: string;
    story: Story;
    canonicalMarkdown: string;
}

export interface ScrumboardResponse {
    scrumboard: WritableScrumboard;
}

/**
 * Shape of a draft returned by the AI structuring endpoint. Same envelope as `CreateStoryBody`
 * (`title` + optional `sections`) so the existing create-story validator gates AI output and
 * human-typed POSTs with one rule.
 */
export interface StoryDraft {
    title: string;
    sections: Partial<Record<StorySectionKey, string>>;
}

export interface StoryDraftRequestBody {
    notes: string;
}

export interface StoryDraftResponse {
    draft: StoryDraft;
}
