import type { DbDriver } from '../types/db.js';
import type { Goal, NewGoal } from '../types/goals.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

export function createGoalRepository(driver: DbDriver) {
    const repository = {
        async getAll(): Promise<Goal[]> {
            return driver.query<Goal>('SELECT * FROM goals ORDER BY created_at DESC');
        },

        async findGoalById(id: string): Promise<Goal | null> {
            const goal = await driver.queryOne<Goal>('SELECT * FROM goals WHERE id = ?', [id]);
            if (!goal) return null;

            const subGoals = await driver.query<Goal>('SELECT * FROM goals WHERE parent_id = ? ORDER BY created_at ASC', id);
            return {
                ...goal,
                sub_goals: subGoals,
            };
        },

        async getGoalById(id: string): Promise<Goal> {
            const goal = await repository.findGoalById(id);
            if (!goal) {
                throw new NotFoundError(`Goal ${id} not found`);
            }
            return goal;
        },

        async create(goal: NewGoal): Promise<Goal> {
            const id = uuidv7();
            await driver.execute(
                'INSERT INTO goals (id, parent_id, title, description, status) VALUES (?, ?, ?, ?, ?)',
                id,
                goal.parent_id ?? null,
                goal.title,
                goal.description ?? null,
                goal.status ?? 'ACTIVE',
            );
            return driver.queryOne<Goal>('SELECT * FROM goals WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created goal: ${id}`),
            });
        },

        async createWithId(id: string, goal: NewGoal): Promise<Goal> {
            await driver.execute(
                'INSERT INTO goals (id, parent_id, title, description, status) VALUES (?, ?, ?, ?, ?)',
                id,
                goal.parent_id ?? null,
                goal.title,
                goal.description ?? null,
                goal.status ?? 'ACTIVE',
            );
            return driver.queryOne<Goal>('SELECT * FROM goals WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created goal: ${id}`),
            });
        },

        async update(id: string, updates: Partial<NewGoal>): Promise<Goal> {
            await repository.getGoalById(id);

            const fields: string[] = [];
            const values: unknown[] = [];

            if ('title' in updates) {
                fields.push('title = ?');
                values.push(updates.title);
            }
            if ('description' in updates) {
                fields.push('description = ?');
                values.push(updates.description ?? null);
            }
            if ('status' in updates) {
                fields.push('status = ?');
                values.push(updates.status);
            }
            if ('parent_id' in updates) {
                fields.push('parent_id = ?');
                values.push(updates.parent_id ?? null);
            }

            if (fields.length === 0) {
                return driver.queryOne<Goal>('SELECT * FROM goals WHERE id = ?', [id], {
                    notFound: () => new Error(`Goal ${id} not found after no-op update`),
                });
            }

            fields.push("updated_at = datetime('now')");
            values.push(id);

            await driver.execute(`UPDATE goals SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return driver.queryOne<Goal>('SELECT * FROM goals WHERE id = ?', [id], {
                notFound: () => new Error(`Goal ${id} not found after update`),
            });
        },

        async delete(id: string): Promise<boolean> {
            const result = await driver.execute('DELETE FROM goals WHERE id = ?', id);
            return result.changes > 0;
        },
    };

    return repository;
}

export type GoalRepository = ReturnType<typeof createGoalRepository>;
